script:
(function () {
  function setGreeting(fullName) {
    const hour = new Date().getHours();
    let timeOfDay = "";
    let emoji = "";

    if (hour >= 5 && hour < 12) {
      timeOfDay = "Good Morning";
      emoji = "☀️";
    } else if (hour >= 12 && hour < 17) {
      timeOfDay = "Good Afternoon";
      emoji = "🌤️";
    } else if (hour >= 17 && hour < 21) {
      timeOfDay = "Good Evening";
      emoji = "🌇";
    } else {
      timeOfDay = "Good Night";
      emoji = "🌙";
    }

    const firstName = (fullName || "there").split(" ")[0];

    const el = root_element.querySelector("#greeting-text");
    if (el) {
      el.innerHTML = `${timeOfDay}, ${firstName} ${emoji}`;
    }
  }

  const bootName =
    frappe?.boot?.full_name ||
    frappe?.boot?.user?.fullname ||
    frappe?.session?.user_fullname ||
    null;

  if (bootName && bootName !== "Guest") {
    setGreeting(bootName);
  } else {
    frappe.call({
      method: "frappe.client.get_value",
      args: {
        doctype: "User",
        filters: { name: frappe.session.user },
        fieldname: "full_name"
      },
      callback: function (r) {
        const name = r?.message?.full_name || "there";
        setGreeting(name);
      }
    });
  }
})();

