script:
// Greeting
const hour = new Date().getHours();
root_element.querySelector('#pm-greeting').textContent =
  hour < 12 ? 'Good morning,' : hour < 17 ? 'Good afternoon,' : 'Good evening,';

// Name
const fullName = frappe.session.user_fullname || frappe.session.user || 'Project Manager';
root_element.querySelector('#pm-username').textContent = fullName;

// Date
const now = new Date();
root_element.querySelector('#pm-date').textContent =
  now.toLocaleDateString('en-GB', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' });

// Open Projects
frappe.db.count('Project', { filters: { status: 'Open' } }).then(count => {
  root_element.querySelector('#pm-stat-open-val').textContent = count;
});

// My Open Tasks
frappe.db.count('Task', {
  filters: [
    ['status', 'in', ['Open', 'Working']],
    ['_assign', 'like', '%' + frappe.session.user + '%']
  ]
}).then(count => {
  root_element.querySelector('#pm-stat-tasks-val').textContent = count;
});

// Overdue Tasks
const today = frappe.datetime.get_today();
frappe.db.count('Task', {
  filters: [
    ['status', 'not in', ['Completed', 'Cancelled']],
    ['exp_end_date', '<', today]
  ]
}).then(count => {
  const el = root_element.querySelector('#pm-stat-overdue-val');
  el.textContent = count;
  if (count > 0) el.classList.add('pm-overdue');
});

