script:
(function() {
    // Use root_element provided by Frappe - NOT document.getElementById
    let closeBtn = root_element.querySelector('#lg-close-btn');
    let body = root_element.querySelector('#lg-body');
    let header = root_element.querySelector('.guide-header');
    let restoreBar = root_element.querySelector('#lg-restore-bar');

    let isOpen = true;

    closeBtn.addEventListener('click', function() {
      body.style.display = 'none';
      header.style.display = 'none';
      restoreBar.style.display = 'flex';
      isOpen = false;
    });

    restoreBar.addEventListener('click', function() {
      body.style.display = 'block';
      header.style.display = 'flex';
      restoreBar.style.display = 'none';
      isOpen = true;
    });

    root_element.querySelectorAll('.status-badge').forEach(function(badge) {
      badge.addEventListener('mouseenter', function() { badge.style.opacity = '0.8'; badge.style.transform = 'translateY(-1px)'; });
      badge.addEventListener('mouseleave', function() { badge.style.opacity = '1'; badge.style.transform = 'translateY(0)'; });
    });
  })();

