script:
(function () {

  var yearSel   = root_element.querySelector("#mr-year");
  var periodSel = root_element.querySelector("#mr-period");

  var chartInstance = null;
  var reportRows    = [];
  var allEmployees  = [];

  // ── Load Chart.js then boot ──────────────────────────────────────────────
  if (window.Chart) {
    boot();
  } else {
    var script    = document.createElement("script");
    script.src    = "https://cdnjs.cloudflare.com/ajax/libs/Chart.js/4.4.1/chart.umd.js";
    script.onload = boot;
    script.onerror = function () { showError("Failed to load Chart.js."); };
    document.head.appendChild(script);
  }

  // ── Build year dropdown then kick off first load ─────────────────────────
  function boot() {
    var currentYear = new Date().getFullYear();
    var years = [currentYear - 1, currentYear, currentYear + 1];

    yearSel.innerHTML = years.map(function (y) {
      return '<option value="' + y + '"' +
        (y === currentYear ? " selected" : "") + ">" + y + "</option>";
    }).join("");

    yearSel.addEventListener("change",   loadReport);
    periodSel.addEventListener("change", filterPeriod);

    loadReport();
  }

  // ── Call the Script Report ───────────────────────────────────────────────
  function loadReport() {
    var year = yearSel.value;
    setLoader(true);

    frappe.call({
      method: "frappe.desk.query_report.run",
      args: {
        report_name: "Monthly Reflection Summary",
        filters: { year: String(year) }
      },
      callback: function (r) {
        if (!r.message || !r.message.result || !r.message.result.length) {
          showError("No submissions found for " + year + ".");
          return;
        }

        // rows come back as objects - use fieldnames directly
        reportRows = r.message.result.map(function (row) {
          return {
            month     : row.month,
            submitted : row.submitted,
            total     : row.total,
            missing   : row.missing,
            pct       : row.pct
          };
        });

        // rebuild period dropdown
        periodSel.innerHTML =
          '<option value="">All periods</option>' +
          reportRows.map(function (r) {
            return '<option value="' + r.month + '">' + r.month + "</option>";
          }).join("");

        // fetch all active employees
        frappe.call({
          method: "frappe.client.get_list",
          args: {
            doctype          : "Employee",
            filters          : { status: "Active" },
            fields           : [
              "name", "employee_name", "designation",
              "department", "custom_reports_to_name"
            ],
            limit_page_length: 500,
            order_by         : "employee_name asc"
          },
          callback: function (emp) {
            allEmployees = emp.message || [];
            setLoader(false);
            renderChart();
            filterPeriod();
          }
        });
      }
    });
  }

  // ── Handle period dropdown change ────────────────────────────────────────
  function filterPeriod() {
    var period = periodSel.value;

    if (period) {
      var row = null;
      for (var i = 0; i < reportRows.length; i++) {
        if (reportRows[i].month === period) { row = reportRows[i]; break; }
      }
      if (!row) return;

      setText("mr-total",     row.total);
      setText("mr-submitted", row.submitted);
      setText("mr-missing",   row.missing);

      root_element.querySelector("#mr-period-label").textContent = period;
      renderMissingTable(period);

    } else {
      // aggregate across all periods
      var totalStaff     = reportRows.length ? reportRows[0].total : 0;
      var totalSubmitted = reportRows.reduce(function (s, r) {
        return s + r.submitted;
      }, 0);

      setText("mr-total",     totalStaff);
      setText("mr-submitted", totalSubmitted);
      setText("mr-missing",   "-");

      root_element.querySelector("#mr-period-label").textContent = "Select a period";
      root_element.querySelector("#mr-missing-table").innerHTML =
        "<div class='text-center text-muted py-3' style='font-size:13px;'>" +
        "Select a review period to see missing employees.</div>";
    }
  }

  // ── Render stacked bar chart ─────────────────────────────────────────────
  function renderChart() {
    var labels    = reportRows.map(function (r) { return r.month; });
    var submitted = reportRows.map(function (r) { return r.submitted; });
    var missing   = reportRows.map(function (r) { return r.missing; });

    if (chartInstance) { chartInstance.destroy(); chartInstance = null; }

    chartInstance = new Chart(
      root_element.querySelector("#mr-chart"),
      {
        type: "bar",
        data: {
          labels  : labels,
          datasets: [
            {
              label          : "Submitted",
              data           : submitted,
              backgroundColor: "#1D9E75",
              borderRadius   : 4,
              stack          : "s"
            },
            {
              label          : "Missing",
              data           : missing,
              backgroundColor: "#E24B4A",
              borderRadius   : 4,
              stack          : "s"
            }
          ]
        },
        options: {
          responsive         : true,
          maintainAspectRatio: false,
          plugins: {
            legend : { display: false },
            tooltip: {
              callbacks: {
                label: function (ctx) {
                  return "  " + ctx.dataset.label + ": " + ctx.parsed.y;
                }
              }
            }
          },
          scales: {
            x: {
              stacked: true,
              grid   : { display: false },
              ticks  : { font: { size: 11 }, autoSkip: false, maxRotation: 45 }
            },
            y: {
              stacked    : true,
              beginAtZero: true,
              ticks      : { font: { size: 11 }, stepSize: 1 },
              grid       : { color: "rgba(128,128,128,0.1)" }
            }
          }
        }
      }
    );
  }

  // ── Render missing employees table ───────────────────────────────────────
  function renderMissingTable(period) {
    var container = root_element.querySelector("#mr-missing-table");
    container.innerHTML =
      "<div class='text-center text-muted py-3'>" +
      "<div class='spinner-border spinner-border-sm me-2'></div>Loading...</div>";

    frappe.call({
      method: "frappe.client.get_list",
      args: {
        doctype          : "Monthly Reflection",
        filters          : { review_period: period },
        fields           : ["employee"],
        limit_page_length: 500
      },
      callback: function (r) {
        var done = {};
        (r.message || []).forEach(function (x) { done[x.employee] = true; });

        var missing = allEmployees.filter(function (e) {
          return !done[e.name];
        });

        if (!missing.length) {
          container.innerHTML =
            "<div class='text-center py-3'>" +
            "<span class='badge rounded-pill px-3 py-2' " +
            "style='background:#e8f8f2; color:#1D9E75; font-size:13px; font-weight:500;'>" +
            "✓ All employees have submitted for " + period +
            "</span></div>";
          return;
        }

        var html =
          "<div class='mb-2'>" +
          "<span class='badge rounded-pill px-3 py-2' " +
          "style='background:#fdecea; color:#c0392b; font-size:12px; font-weight:500;'>" +
          missing.length + " employee(s) pending</span></div>" +
          "<div class='table-responsive'>" +
          "<table class='table table-sm table-hover mb-0'>" +
          "<thead class='table-light'><tr>" +
          "<th style='width:36px;'>#</th>" +
          "<th>Employee</th>" +
          "<th>Department</th>" +
          "<th>Job Title</th>" +
          "<th>Supervisor</th>" +
          "</tr></thead><tbody>";

        missing.forEach(function (e, i) {
          html +=
            "<tr>" +
            "<td class='text-muted'>" + (i + 1) + "</td>" +
            "<td><a href='/app/employee/" + e.name + "' target='_blank' " +
            "class='text-decoration-none fw-500'>" +
            (e.employee_name || e.name) + "</a></td>" +
            "<td class='text-muted'>" + (e.department             || "-") + "</td>" +
            "<td class='text-muted'>" + (e.designation            || "-") + "</td>" +
            "<td class='text-muted'>" + (e.custom_reports_to_name || "-") + "</td>" +
            "</tr>";
        });

        html += "</tbody></table></div>";
        container.innerHTML = html;
      }
    });
  }

  // ── Helpers ──────────────────────────────────────────────────────────────
  function setLoader(show) {
    root_element.querySelector("#mr-loader").style.display  = show ? "block" : "none";
    root_element.querySelector("#mr-content").style.display = show ? "none"  : "block";
  }

  function setText(id, val) {
    root_element.querySelector("#" + id).textContent = val;
  }

  function showError(msg) {
    root_element.querySelector("#mr-loader").style.display = "block";
    root_element.querySelector("#mr-loader").innerHTML =
      "<div class='alert alert-warning m-3 text-start'>" + msg + "</div>";
  }

})();

