  padding: 12px 0;
}

script:
(function() {
    // Use root_element provided by Frappe's shadow DOM - NOT document.getElementById
    let closeBtn = root_element.querySelector('#og-close-btn');
    let body = root_element.querySelector('#og-body');
    let header = root_element.querySelector('#og-header');
    let restoreBar = root_element.querySelector('#og-restore-bar');

    let isOpen = true;

    closeBtn.addEventListener('click', function() {
      body.style.display = 'none';
      header.style.display = 'none';
      restoreBar.style.display = 'flex';
      isOpen = false;
    });

    restoreBar.addEventListener('click', function() {
      body.style.display = 'block';
      header.style.display = 'flex';
      restoreBar.style.display = 'none';
      isOpen = true;
    });

    root_element.querySelectorAll('.status-badge').forEach(function(badge) {
      badge.addEventListener('mouseenter', function() { badge.style.opacity = '0.8'; badge.style.transform = 'translateY(-1px)'; });
      badge.addEventListener('mouseleave', function() { badge.style.opacity = '1'; badge.style.transform = 'translateY(0)'; });
    });

    root_element.querySelectorAll('.info-card').forEach(function(card) {
      card.addEventListener('mouseenter', function() { card.style.opacity = '0.85'; card.style.transform = 'translateY(-1px)'; });
      card.addEventListener('mouseleave', function() { card.style.opacity = '1'; card.style.transform = 'translateY(0)'; });
    });
  })();

